import React from 'react';
import { FlaskConical, Code2, Bug, LayoutDashboard, ChevronRight } from 'lucide-react';

const navItems = [
  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
  { id: 'testcases', label: 'Test Cases', icon: FlaskConical },
  { id: 'automation', label: 'Automation', icon: Code2 },
  { id: 'bugreports', label: 'Bug Reports', icon: Bug },
];

export default function Sidebar({ activePage, onNavigate }) {
  return (
    <aside style={{
      width: '240px',
      position: 'fixed',
      top: 0,
      left: 0,
      height: '100vh',
      background: '#fff',
      borderRight: '1px solid #e2e0f0',
      display: 'flex',
      flexDirection: 'column',
      padding: '0',
      zIndex: 100,
    }}>
      {/* Logo */}
      <div style={{
        padding: '20px 20px 16px',
        borderBottom: '1px solid #f0eff8',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <div style={{
            width: 34,
            height: 34,
            background: '#534AB7',
            borderRadius: 8,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}>
            <FlaskConical size={18} color="white" />
          </div>
          <div>
            <div style={{ fontWeight: 700, fontSize: 15, color: '#1a1a2e', lineHeight: 1.2 }}>QA Assistant</div>
            <div style={{ fontSize: 11, color: '#888' }}>AI-Powered Testing</div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav style={{ padding: '12px 10px', flex: 1 }}>
        <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.08em', color: '#aaa', padding: '4px 10px 8px' }}>
          Main Menu
        </div>
        {navItems.map(({ id, label, icon: Icon }) => {
          const active = activePage === id;
          return (
            <button
              key={id}
              onClick={() => onNavigate(id)}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 10,
                width: '100%',
                padding: '9px 12px',
                borderRadius: 8,
                border: 'none',
                cursor: 'pointer',
                fontSize: 13,
                fontWeight: active ? 600 : 400,
                color: active ? '#534AB7' : '#444',
                background: active ? '#EEEDFE' : 'transparent',
                marginBottom: 2,
                textAlign: 'left',
                transition: 'all 0.15s',
              }}
              onMouseEnter={e => { if (!active) e.currentTarget.style.background = '#f5f4fc'; }}
              onMouseLeave={e => { if (!active) e.currentTarget.style.background = 'transparent'; }}
            >
              <Icon size={16} />
              <span style={{ flex: 1 }}>{label}</span>
              {active && <ChevronRight size={14} />}
            </button>
          );
        })}
      </nav>

      {/* Footer */}
      <div style={{
        padding: '16px 20px',
        borderTop: '1px solid #f0eff8',
      }}>
        <div style={{
          background: '#EEEDFE',
          borderRadius: 8,
          padding: '10px 12px',
        }}>
          <div style={{ fontSize: 12, fontWeight: 600, color: '#534AB7' }}>Phase 1 · Active</div>
          <div style={{ fontSize: 11, color: '#7F77DD', marginTop: 2 }}>Core QA features enabled</div>
        </div>
      </div>
    </aside>
  );
}
